import{_ as o,c as e,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AI 에이전트: 10명의 전문가 소개 | oh-my-opencode","description":"oh-my-opencode의 10개 AI 에이전트를 학습하세요. 작업 유형에 따라 에이전트를 선택하여 효율적인 협업과 병렬 실행을 구현합니다.","frontmatter":{"title":"AI 에이전트: 10명의 전문가 소개 | oh-my-opencode","sidebarTitle":"10명의 AI 전문가 소개","subtitle":"AI 에이전트: 10명의 전문가 소개","description":"oh-my-opencode의 10개 AI 에이전트를 학습하세요. 작업 유형에 따라 에이전트를 선택하여 효율적인 협업과 병렬 실행을 구현합니다.","tags":["ai-agents","orchestration"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"ko/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"ko/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),n={name:"ko/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function r(l,t,i,d,p,g){return s(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="ai-에이전트-팀-10명의-전문가-소개" tabindex="-1">AI 에이전트 팀: 10명의 전문가 소개 <a class="header-anchor" href="#ai-에이전트-팀-10명의-전문가-소개" aria-label="Permalink to &quot;AI 에이전트 팀: 10명의 전문가 소개&quot;">​</a></h1><h2 id="이-과정에서-배울-수-있는-것" tabindex="-1">이 과정에서 배울 수 있는 것 <a class="header-anchor" href="#이-과정에서-배울-수-있는-것" aria-label="Permalink to &quot;이 과정에서 배울 수 있는 것&quot;">​</a></h2><ul><li>10개 내장 AI 에이전트의 역할과 전문 분야 이해</li><li>작업 유형에 따라 가장 적합한 에이전트 빠르게 선택</li><li>에이전트 간 협업 메커니즘 이해(위임, 병렬, 검토)</li><li>다양한 에이전트의 권한 제한과 사용 시나리오 마스터</li></ul><h2 id="핵심-아이디어-실제-팀처럼-협업하기" tabindex="-1">핵심 아이디어: 실제 팀처럼 협업하기 <a class="header-anchor" href="#핵심-아이디어-실제-팀처럼-협업하기" aria-label="Permalink to &quot;핵심 아이디어: 실제 팀처럼 협업하기&quot;">​</a></h2><p><strong>oh-my-opencode</strong>의 핵심 아이디어는: <strong>AI를 만능 도우미가 아니라 전문 팀으로 간주하세요</strong>.</p><p>실제 개발 팀에서는 다음이 필요합니다:</p><ul><li><strong>메인 오케스트레이터</strong>(Tech Lead): 계획, 작업 할당, 진행 추적 담당</li><li><strong>아키텍처 고문</strong>(Architect): 기술 의사결정과 아키텍처 설계 제안 제공</li><li><strong>코드 리뷰</strong>(Reviewer): 코드 품질 확인, 잠재적 문제 발견</li><li><strong>연구 전문가</strong>(Researcher): 문서 찾기, 오픈소스 구현 검색, 베스트 프랙티스 조사</li><li><strong>코드 탐정</strong>(Searcher): 코드 빠른 위치 확인, 참조 찾기, 기존 구현 이해</li><li><strong>프론트엔드 디자이너</strong>(Frontend Designer): UI 설계, 스타일 조정</li><li><strong>Git 전문가</strong>(Git Master): 코드 커밋, 브랜치 관리, 기록 검색</li></ul><p>oh-my-opencode는 이러한 역할을 10개 전문 AI 에이전트로 만들어, 작업 유형에 따라 유연하게 조합하여 사용할 수 있습니다.</p><h2 id="_10개-에이전트-상세-설명" tabindex="-1">10개 에이전트 상세 설명 <a class="header-anchor" href="#_10개-에이전트-상세-설명" aria-label="Permalink to &quot;10개 에이전트 상세 설명&quot;">​</a></h2><h3 id="메인-오케스트레이터-2개" tabindex="-1">메인 오케스트레이터(2개) <a class="header-anchor" href="#메인-오케스트레이터-2개" aria-label="Permalink to &quot;메인 오케스트레이터(2개)&quot;">​</a></h3><h4 id="sisyphus-메인-오케스트레이터" tabindex="-1">Sisyphus - 메인 오케스트레이터 <a class="header-anchor" href="#sisyphus-메인-오케스트레이터" aria-label="Permalink to &quot;Sisyphus - 메인 오케스트레이터&quot;">​</a></h4><p><strong>역할</strong>: 메인 오케스트레이터, 주요 기술 책임자</p><p><strong>능력</strong>:</p><ul><li>심층 추론(32k thinking budget)</li><li>복잡한 작업 계획 및 위임</li><li>코드 수정 및 리팩토링 실행</li><li>전체 개발 프로세스 관리</li></ul><p><strong>추천 모델</strong>: <code>anthropic/claude-opus-4-5</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>일일 개발 작업(새 기능 추가, 버그 수정)</li><li>심층 추론이 필요한 복잡한 문제</li><li>다단계 작업 분해 및 실행</li><li>다른 에이전트를 병렬로 위임해야 하는 시나리오</li></ul><p><strong>호출 방식</strong>:</p><ul><li>기본 메인 에이전트(OpenCode Agent 선택기의 &quot;Sisyphus&quot;)</li><li>프롬프트에 직접 작업 입력, 특수 트리거 불필요</li></ul><p><strong>권한</strong>: 전체 도구 권한(write, edit, bash, delegate_task 등)</p><hr><h4 id="atlas-todo-관리자" tabindex="-1">Atlas - TODO 관리자 <a class="header-anchor" href="#atlas-todo-관리자" aria-label="Permalink to &quot;Atlas - TODO 관리자&quot;">​</a></h4><p><strong>역할</strong>: 메인 오케스트레이터, TODO 목록 관리와 작업 실행 추적에 집중</p><p><strong>능력</strong>:</p><ul><li>TODO 목록 관리 및 추적</li><li>체계적인 계획 실행</li><li>작업 진행 상황 모니터링</li></ul><p><strong>추천 모델</strong>: <code>anthropic/claude-opus-4-5</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li><code>/start-work</code> 명령으로 프로젝트 실행 시작</li><li>계획에 따라 작업 완료 필요</li><li>체계적인 작업 진행 상황 추적</li></ul><p><strong>호출 방식</strong>:</p><ul><li>슬래시 명령 <code>/start-work</code> 사용</li><li>Atlas Hook을 통해 자동 활성화</li></ul><p><strong>권한</strong>: 전체 도구 권한</p><hr><h3 id="고문-및-검토-3개" tabindex="-1">고문 및 검토(3개) <a class="header-anchor" href="#고문-및-검토-3개" aria-label="Permalink to &quot;고문 및 검토(3개)&quot;">​</a></h3><h4 id="oracle-전략-고문" tabindex="-1">Oracle - 전략 고문 <a class="header-anchor" href="#oracle-전략-고문" aria-label="Permalink to &quot;Oracle - 전략 고문&quot;">​</a></h4><p><strong>역할</strong>: 읽기 전용 기술 고문, 고지능 추론 전문가</p><p><strong>능력</strong>:</p><ul><li>아키텍처 의사결정 제안</li><li>복잡한 문제 진단</li><li>코드 리뷰(읽기 전용)</li><li>다중 시스템 트레이드오프 분석</li></ul><p><strong>추천 모델</strong>: <code>openai/gpt-5.2</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>복잡한 아키텍처 설계</li><li>중요 작업 완료 후 자가 검토</li><li>2회 이상 수정 실패한 어려운 디버깅</li><li>낯선 코드 패턴이나 아키텍처</li><li>보안/성능 관련 문제</li></ul><p><strong>트리거 조건</strong>:</p><ul><li>프롬프트에 <code>@oracle</code> 포함 또는 <code>delegate_task(agent=&quot;oracle&quot;)</code> 사용</li><li>복잡한 아키텍처 의사결정 시 자동 추천</li></ul><p><strong>제한</strong>: 읽기 전용 권한(write, edit, task, delegate_task 금지)</p><p><strong>핵심 원칙</strong>:</p><ul><li><strong>미니멀리즘</strong>: 가장 간단한 해결책 선호</li><li><strong>기존 리소스 활용</strong>: 현재 코드 우선 수정, 새 의존성 도입 피하기</li><li><strong>개발자 경험 우선</strong>: 가독성, 유지보수성 &gt; 이론적 성능</li><li><strong>단일 명확한 경로</strong>: 하나의 주요 제안 제공, 트레이드오프 차이가 뚜렷할 때만 대안 제시</li></ul><hr><h4 id="metis-사전-계획-분석가" tabindex="-1">Metis - 사전 계획 분석가 <a class="header-anchor" href="#metis-사전-계획-분석가" aria-label="Permalink to &quot;Metis - 사전 계획 분석가&quot;">​</a></h4><p><strong>역할</strong>: 계획 전 요구사항 분석 및 위험 평가 전문가</p><p><strong>능력</strong>:</p><ul><li>숨겨진 요구사항과 명확하지 않은 요구사항 식별</li><li>AI 실패로 이어질 수 있는 모호성 감지</li><li>잠재적 AI-slop 패턴 표시(과도한 엔지니어링, 범위 확장)</li><li>계획 에이전트를 위한 지침 준비</li></ul><p><strong>추천 모델</strong>: <code>anthropic/claude-sonnet-4-5</code>(temperature: 0.3)</p><p><strong>사용 시나리오</strong>:</p><ul><li>Prometheus 계획 전</li><li>사용자 요청이 모호하거나 개방형일 때</li><li>AI 과도한 엔지니어링 패턴 방지</li></ul><p><strong>호출 방식</strong>: Prometheus 자동 호출(인터뷰 모드)</p><p><strong>제한</strong>: 읽기 전용 권한(write, edit, task, delegate_task 금지)</p><p><strong>핵심 프로세스</strong>:</p><ol><li><strong>의도 분류</strong>: 리팩토링 / 처음부터 구축 / 중간 작업 / 협업 / 아키텍처 / 연구</li><li><strong>의도 특정 분석</strong>: 다양한 유형에 따라 맞춤형 제안 제공</li><li><strong>질문 생성</strong>: 사용자를 위해 명확한 질문 생성</li><li><strong>지침 준비</strong>: Prometheus를 위해 명확한 &quot;MUST&quot; 및 &quot;MUST NOT&quot; 지침 생성</li></ol><hr><h4 id="momus-계획-검토자" tabindex="-1">Momus - 계획 검토자 <a class="header-anchor" href="#momus-계획-검토자" aria-label="Permalink to &quot;Momus - 계획 검토자&quot;">​</a></h4><p><strong>역할</strong>: 엄격한 계획 검토 전문가, 누락된 모든 항목과 모호한 점 발견</p><p><strong>능력</strong>:</p><ul><li>계획의 명확성, 검증 가능성, 완전성 검증</li><li>모든 파일 참조 및 컨텍스트 확인</li><li>실제 구현 단계 시뮬레이션</li><li>중요한 누락 항목 식별</li></ul><p><strong>추천 모델</strong>: <code>anthropic/claude-sonnet-4-5</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>Prometheus 작업 계획 생성 후</li><li>복잡한 TODO 목록 실행 전</li><li>계획 품질 검증</li></ul><p><strong>호출 방식</strong>: Prometheus 자동 호출</p><p><strong>제한</strong>: 읽기 전용 권한(write, edit, task, delegate_task 금지)</p><p><strong>4대 검토 기준</strong>:</p><ol><li><strong>작업 내용 명확성</strong>: 각 작업이 참조 소스를 지정했는가?</li><li><strong>검증 및 수락 기준</strong>: 구체적인 성공 검증 방법이 있는가?</li><li><strong>컨텍스트 완전성</strong>: 충분한 컨텍스트 제공(90% 신뢰도 임계값)?</li><li><strong>전체 이해</strong>: 개발자가 WHY, WHAT, HOW를 이해하는가?</li></ol><p><strong>핵심 원칙</strong>: <strong>문서 검토자, 디자인 고문이 아님</strong>. &quot;선택한 방법이 올바른가&quot;가 아니라 &quot;계획이 실행 가능할 만큼 명확한가&quot;를 평가합니다.</p><hr><h3 id="연구-및-탐색-3개" tabindex="-1">연구 및 탐색(3개) <a class="header-anchor" href="#연구-및-탐색-3개" aria-label="Permalink to &quot;연구 및 탐색(3개)&quot;">​</a></h3><h4 id="librarian-다중-리포지토리-연구-전문가" tabindex="-1">Librarian - 다중 리포지토리 연구 전문가 <a class="header-anchor" href="#librarian-다중-리포지토리-연구-전문가" aria-label="Permalink to &quot;Librarian - 다중 리포지토리 연구 전문가&quot;">​</a></h4><p><strong>역할</strong>: 오픈소스 코드 라이브러리 이해 전문가, 문서와 구현 예제 찾기 전문</p><p><strong>능력</strong>:</p><ul><li>GitHub CLI: 리포지토리 클론, 이슈/PR 검색, 기록 확인</li><li>Context7: 공식 문서 쿼리</li><li>Web Search: 최신 정보 검색</li><li>영구 링크가 포함된 증거 생성</li></ul><p><strong>추천 모델</strong>: <code>opencode/big-pickle</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>&quot;[라이브러리]를 어떻게 사용하는가?&quot;</li><li>&quot;[프레임워크 기능]의 베스트 프랙티스는 무엇인가?&quot;</li><li>&quot;[외부 의존성]이 왜 이렇게 동작하는가?&quot;</li><li>&quot;[라이브러리]의 사용 예제 찾기&quot;</li></ul><p><strong>트리거 조건</strong>:</p><ul><li>외부 라이브러리/소스 언급 시 자동 트리거</li><li>프롬프트에 <code>@librarian</code> 포함</li></ul><p><strong>요청 유형 분류</strong>:</p><ul><li><strong>Type A(개념적)</strong>: &quot;X를 어떻게 하는가?&quot;, &quot;베스트 프랙티스&quot;</li><li><strong>Type B(구현 참조)</strong>: &quot;X가 Y를 어떻게 구현하는가?&quot;, &quot;Z의 소스코드 보여줘&quot;</li><li><strong>Type C(컨텍스트 및 기록)</strong>: &quot;왜 이렇게 변경했는가?&quot;, &quot;X의 기록?&quot;</li><li><strong>Type D(종합 연구)</strong>: 복잡/모호한 요청</li></ul><p><strong>제한</strong>: 읽기 전용 권한(write, edit, task, delegate_task, call_omo_agent 금지)</p><p><strong>필수 요구사항</strong>: 모든 코드 선언은 GitHub 영구 링크를 포함해야 함</p><hr><h4 id="explore-빠른-코드베이스-탐색-전문가" tabindex="-1">Explore - 빠른 코드베이스 탐색 전문가 <a class="header-anchor" href="#explore-빠른-코드베이스-탐색-전문가" aria-label="Permalink to &quot;Explore - 빠른 코드베이스 탐색 전문가&quot;">​</a></h4><p><strong>역할</strong>: 컨텍스트 인식 코드 검색 전문가</p><p><strong>능력</strong>:</p><ul><li>LSP 도구: 정의, 참조, 심볼 네비게이션</li><li>AST-Grep: 구조적 패턴 검색</li><li>Grep: 텍스트 패턴 검색</li><li>Glob: 파일명 패턴 매칭</li><li>병렬 실행(3개 이상 도구 동시 실행)</li></ul><p><strong>추천 모델</strong>: <code>opencode/gpt-5-nano</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>2개 이상 검색 각도가 필요한 광범위한 검색</li><li>낯선 모듈 구조</li><li>계층 간 패턴 발견</li><li>&quot;X가 어디에 있는가?&quot;, &quot;어떤 파일에 Y가 있는가?&quot; 찾기</li></ul><p><strong>트리거 조건</strong>:</p><ul><li>2개 이상 모듈 관련 시 자동 트리거</li><li>프롬프트에 <code>@explore</code> 포함</li></ul><p><strong>필수 출력 형식</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [사용자 문자 그대로 요청]</span></span>
<span class="line"><span>**Actual Need**: [실제 필요한 것]</span></span>
<span class="line"><span>**Success Looks Like**: [성공이 어떻게 보이는지]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [이 파일이 관련되는 이유]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [이 파일이 관련되는 이유]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[실제 요구사항에 대한 직접 답변]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[다음에 무엇을 해야 하는지]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>제한</strong>: 읽기 전용 권한(write, edit, task, delegate_task, call_omo_agent 금지)</p><hr><h4 id="multimodal-looker-미디어-분석-전문가" tabindex="-1">Multimodal Looker - 미디어 분석 전문가 <a class="header-anchor" href="#multimodal-looker-미디어-분석-전문가" aria-label="Permalink to &quot;Multimodal Looker - 미디어 분석 전문가&quot;">​</a></h4><p><strong>역할</strong>: 텍스트로 읽을 수 없는 미디어 파일 설명</p><p><strong>능력</strong>:</p><ul><li>PDF: 텍스트, 구조, 테이블, 특정 섹션 데이터 추출</li><li>이미지: 레이아웃, UI 요소, 텍스트, 차트 설명</li><li>차트: 관계, 프로세스, 아키텍처 설명</li></ul><p><strong>추천 모델</strong>: <code>google/gemini-3-flash</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>PDF에서 구조화된 데이터 추출 필요</li><li>이미지의 UI 요소나 차트 설명</li><li>기술 문서의 차트 분석</li></ul><p><strong>호출 방식</strong>: <code>look_at</code> 도구를 통해 자동 트리거</p><p><strong>제한</strong>: <strong>읽기 전용 허용목록</strong>(read 도구만 허용)</p><hr><h3 id="계획-및-실행-2개" tabindex="-1">계획 및 실행(2개) <a class="header-anchor" href="#계획-및-실행-2개" aria-label="Permalink to &quot;계획 및 실행(2개)&quot;">​</a></h3><h4 id="prometheus-전략-계획가" tabindex="-1">Prometheus - 전략 계획가 <a class="header-anchor" href="#prometheus-전략-계획가" aria-label="Permalink to &quot;Prometheus - 전략 계획가&quot;">​</a></h4><p><strong>역할</strong>: 인터뷰식 요구사항 수집 및 작업 계획 생성 전문가</p><p><strong>능력</strong>:</p><ul><li>인터뷰 모드: 요구사항이 명확해질 때까지 지속적인 질문</li><li>작업 계획 생성: 구조화된 Markdown 계획 문서</li><li>병렬 위임: Oracle, Metis, Momus에 계획 검토 요청</li></ul><p><strong>추천 모델</strong>: <code>anthropic/claude-opus-4-5</code>(temperature: 0.1)</p><p><strong>사용 시나리오</strong>:</p><ul><li>복잡한 프로젝트를 위한 상세 계획 수립</li><li>명확한 요구사항이 필요한 프로젝트</li><li>체계적인 워크플로우</li></ul><p><strong>호출 방식</strong>:</p><ul><li>프롬프트에 <code>@prometheus</code> 또는 &quot;Prometheus 사용&quot; 포함</li><li>슬래시 명령 <code>/start-work</code> 사용</li></ul><p><strong>워크플로우</strong>:</p><ol><li><strong>인터뷰 모드</strong>: 요구사항이 명확해질 때까지 지속적인 질문</li><li><strong>계획 초안</strong>: 구조화된 Markdown 계획 생성</li><li><strong>병렬 위임</strong>: <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;아키텍처 의사결정 검토&quot;)</code> → 백그라운드 실행</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;잠재적 위험 식별&quot;)</code> → 백그라운드 실행</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;계획 완전성 검증&quot;)</code> → 백그라운드 실행</li></ul></li><li><strong>피드백 통합</strong>: 계획 개선</li><li><strong>계획 출력</strong>: <code>.sisyphus/plans/{name}.md</code>에 저장</li></ol><p><strong>제한</strong>: 계획만 하고 코드는 구현하지 않음(<code>prometheus-md-only</code> Hook이 강제)</p><hr><h4 id="sisyphus-junior-작업-실행자" tabindex="-1">Sisyphus Junior - 작업 실행자 <a class="header-anchor" href="#sisyphus-junior-작업-실행자" aria-label="Permalink to &quot;Sisyphus Junior - 작업 실행자&quot;">​</a></h4><p><strong>역할</strong>: 카테고리 생성 자식 에이전트 실행자</p><p><strong>능력</strong>:</p><ul><li>Category 구성 상속(모델, temperature, prompt_append)</li><li>Skills 로드(전문 기술)</li><li>위임된 하위 작업 실행</li></ul><p><strong>추천 모델</strong>: Category에서 상속(기본 <code>anthropic/claude-sonnet-4-5</code>)</p><p><strong>사용 시나리오</strong>:</p><ul><li><code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code> 사용 시 자동 생성</li><li>특정 Category와 Skill 조합이 필요한 작업</li><li>가벼운 빠른 작업(&quot;quick&quot; Category는 Haiku 모델 사용)</li></ul><p><strong>호출 방식</strong>: <code>delegate_task</code> 도구를 통해 자동 생성</p><p><strong>제한</strong>: task, delegate_task 금지(다시 위임 불가)</p><hr><h2 id="에이전트-호출-방식-요약" tabindex="-1">에이전트 호출 방식 요약 <a class="header-anchor" href="#에이전트-호출-방식-요약" aria-label="Permalink to &quot;에이전트 호출 방식 요약&quot;">​</a></h2><table tabindex="0"><thead><tr><th>에이전트</th><th>호출 방식</th><th>트리거 조건</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>기본 메인 에이전트</td><td>일일 개발 작업</td></tr><tr><td><strong>Atlas</strong></td><td><code>/start-work</code> 명령</td><td>프로젝트 실행 시작</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> 또는 <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>복잡한 아키텍처 의사결정, 2회 이상 수정 실패</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> 또는 <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>외부 라이브러리/소스 언급 시 자동 트리거</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> 또는 <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>2개 이상 모듈 관련 시 자동 트리거</td></tr><tr><td><strong>Multimodal Looker</strong></td><td><code>look_at</code> 도구</td><td>PDF/이미지 분석 필요 시</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> 또는 <code>/start-work</code></td><td>프롬프트에 &quot;Prometheus&quot; 포함 또는 계획 필요</td></tr><tr><td><strong>Metis</strong></td><td>Prometheus 자동 호출</td><td>계획 전 자동 분석</td></tr><tr><td><strong>Momus</strong></td><td>Prometheus 자동 호출</td><td>계획 생성 후 자동 검토</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>Category/Skill 사용 시 자동 생성</td></tr></tbody></table><hr><h2 id="어떤-에이전트를-언제-사용할-것인가" tabindex="-1">어떤 에이전트를 언제 사용할 것인가 <a class="header-anchor" href="#어떤-에이전트를-언제-사용할-것인가" aria-label="Permalink to &quot;어떤 에이전트를 언제 사용할 것인가&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">빠른 의사결정 트리</p><p><strong>시나리오 1: 일일 개발(코드 작성, 버그 수정)</strong> → <strong>Sisyphus</strong>(기본)</p><p><strong>시나리오 2: 복잡한 아키텍처 의사결정</strong> → <strong>@oracle</strong> 자문</p><p><strong>시나리오 3: 외부 라이브러리의 문서나 구현을 찾아야 할 때</strong> → <strong>@librarian</strong> 또는 자동 트리거</p><p><strong>시나리오 4: 낯선 코드베이스, 관련 코드 찾기 필요</strong> → <strong>@explore</strong> 또는 자동 트리거(2개 이상 모듈)</p><p><strong>시나리오 5: 복잡한 프로젝트에 상세 계획 필요</strong> → <strong>@prometheus</strong> 또는 <code>/start-work</code> 사용</p><p><strong>시나리오 6: PDF나 이미지 분석 필요</strong> → <code>look_at</code> 도구(자동으로 Multimodal Looker 트리거)</p><p><strong>시나리오 7: 빠르고 간단한 작업, 비용 절감</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>시나리오 8: Git 전문 작업 필요</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>시나리오 9: 프론트엔드 UI 디자인 필요</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>시나리오 10: 고지능 추론 작업 필요</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="에이전트-협업-예제-완전-워크플로우" tabindex="-1">에이전트 협업 예제: 완전 워크플로우 <a class="header-anchor" href="#에이전트-협업-예제-완전-워크플로우" aria-label="Permalink to &quot;에이전트 협업 예제: 완전 워크플로우&quot;">​</a></h2><h3 id="예제-1-복잡한-기능-개발" tabindex="-1">예제 1: 복잡한 기능 개발 <a class="header-anchor" href="#예제-1-복잡한-기능-개발" aria-label="Permalink to &quot;예제 1: 복잡한 기능 개발&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자: 사용자 인증 시스템 개발</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphus 작업 수신</span></span>
<span class="line"><span>  → 요구사항 분석, 외부 라이브러리 필요(JWT) 확인</span></span>
<span class="line"><span>  → 병렬 위임:</span></span>
<span class="line"><span>    - @librarian: &quot;Next.js JWT 베스트 프랙티스 찾기&quot; → [백그라운드]</span></span>
<span class="line"><span>    - @explore: &quot;기존 인증 관련 코드 찾기&quot; → [백그라운드]</span></span>
<span class="line"><span>  → 결과 대기, 정보 통합</span></span>
<span class="line"><span>  → JWT 인증 기능 구현</span></span>
<span class="line"><span>  → 완료 후 위임:</span></span>
<span class="line"><span>    - @oracle: &quot;아키텍처 설계 검토&quot; → [백그라운드]</span></span>
<span class="line"><span>  → 제안에 따라 최적화</span></span></code></pre></div><hr><h3 id="예제-2-프로젝트-계획" tabindex="-1">예제 2: 프로젝트 계획 <a class="header-anchor" href="#예제-2-프로젝트-계획" aria-label="Permalink to &quot;예제 2: 프로젝트 계획&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자: Prometheus로 이 프로젝트 계획 세우기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheus 작업 수신</span></span>
<span class="line"><span>  → 인터뷰 모드:</span></span>
<span class="line"><span>    - 질문 1: 핵심 기능은 무엇인가?</span></span>
<span class="line"><span>    - [사용자 답변]</span></span>
<span class="line"><span>    - 질문 2: 타겟 사용자 그룹?</span></span>
<span class="line"><span>    - [사용자 답변]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → 요구사항 명확해진 후 병렬 위임:</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;아키텍처 의사결정 검토&quot;) → [백그라운드]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;잠재적 위험 식별&quot;) → [백그라운드]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;계획 완전성 검증&quot;) → [백그라운드]</span></span>
<span class="line"><span>  → 모든 백그라운드 작업 완료 대기</span></span>
<span class="line"><span>  → 피드백 통합, 계획 개선</span></span>
<span class="line"><span>  → Markdown 계획 문서 출력</span></span>
<span class="line"><span>→ 사용자 계획 확인</span></span>
<span class="line"><span>→ /start-work로 실행 시작</span></span></code></pre></div><hr><h2 id="에이전트-권한-및-제한" tabindex="-1">에이전트 권한 및 제한 <a class="header-anchor" href="#에이전트-권한-및-제한" aria-label="Permalink to &quot;에이전트 권한 및 제한&quot;">​</a></h2><table tabindex="0"><thead><tr><th>에이전트</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="이-과정-요약" tabindex="-1">이 과정 요약 <a class="header-anchor" href="#이-과정-요약" aria-label="Permalink to &quot;이 과정 요약&quot;">​</a></h2><p>oh-my-opencode의 10개 AI 에이전트는 개발 프로세스의 모든 단계를 포괄합니다:</p><ul><li><strong>오케스트레이션 및 실행</strong>: Sisyphus(메인 오케스트레이터), Atlas(TODO 관리)</li><li><strong>고문 및 검토</strong>: Oracle(전략 고문), Metis(사전 계획 분석), Momus(계획 검토)</li><li><strong>연구 및 탐색</strong>: Librarian(다중 리포지토리 연구), Explore(코드베이스 탐색), Multimodal Looker(미디어 분석)</li><li><strong>계획</strong>: Prometheus(전략 계획), Sisyphus Junior(하위 작업 실행)</li></ul><p><strong>핵심 요점</strong>:</p><ol><li>AI를 만능 도우미가 아니라 전문 팀으로 간주하세요</li><li>작업 유형에 따라 가장 적합한 에이전트를 선택하세요</li><li>병렬 위임을 활용하여 효율성 높이기(Librarian, Explore, Oracle은 백그라운드에서 실행 가능)</li><li>각 에이전트의 권한 제한 이해(읽기 전용 에이전트는 코드 수정 불가)</li><li>에이전트 간 협업으로 완전 워크플로우 형성(계획 → 실행 → 검토)</li></ol><hr><h2 id="다음-과정-미리보기" tabindex="-1">다음 과정 미리보기 <a class="header-anchor" href="#다음-과정-미리보기" aria-label="Permalink to &quot;다음 과정 미리보기&quot;">​</a></h2><blockquote><p>다음 과정에서는 **<a href="./../prometheus-planning/">Prometheus 계획: 인터뷰식 요구사항 수집</a>**를 학습합니다.</p><p>다음을 배우게 됩니다:</p><ul><li>Prometheus를 사용하여 인터뷰식 요구사항 수집 방법</li><li>구조화된 작업 계획 생성 방법</li><li>Metis와 Momus가 계획을 검토하도록 하는 방법</li><li>백그라운드 작업 가져오기 및 취소 방법</li></ul></blockquote><hr><h2 id="부록-소스코드-참조" tabindex="-1">부록: 소스코드 참조 <a class="header-anchor" href="#부록-소스코드-참조" aria-label="Permalink to &quot;부록: 소스코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스코드 위치 펼치기</strong></summary><blockquote><p>업데이트 시간: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>에이전트</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>Sisyphus 메인 오케스트레이터</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Atlas 메인 오케스트레이터</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Oracle 고문</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Librarian 연구 전문가</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Explore 검색 전문가</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Prometheus 계획가</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Metis 사전 계획 분석</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Momus 계획 검토자</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>에이전트 메타데이터 정의</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>에이전트 도구 제한</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>핵심 구성</strong>:</p><ul><li><code>ORACLE_PROMPT_METADATA</code>: Oracle 에이전트의 메타데이터(트리거 조건, 사용 시나리오)</li><li><code>LIBRARIAN_PROMPT_METADATA</code>: Librarian 에이전트의 메타데이터</li><li><code>EXPLORE_PROMPT_METADATA</code>: Explore 에이전트의 메타데이터</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>: Multimodal Looker 에이전트의 메타데이터</li><li><code>METIS_SYSTEM_PROMPT</code>: Metis 에이전트의 시스템 프롬프트</li><li><code>MOMUS_SYSTEM_PROMPT</code>: Momus 에이전트의 시스템 프롬프트</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>createOracleAgent(model)</code>: Oracle 에이전트 구성 생성</li><li><code>createLibrarianAgent(model)</code>: Librarian 에이전트 구성 생성</li><li><code>createExploreAgent(model)</code>: Explore 에이전트 구성 생성</li><li><code>createMultimodalLookerAgent(model)</code>: Multimodal Looker 에이전트 구성 생성</li><li><code>createMetisAgent(model)</code>: Metis 에이전트 구성 생성</li><li><code>createMomusAgent(model)</code>: Momus 에이전트 구성 생성</li></ul><p><strong>권한 제한</strong>:</p><ul><li><code>createAgentToolRestrictions()</code>: 에이전트 도구 제한 생성(Oracle, Librarian, Explore, Metis, Momus 사용)</li><li><code>createAgentToolAllowlist()</code>: 에이전트 도구 허용목록 생성(Multimodal Looker 사용)</li></ul></details>`,160)])])}const h=o(n,[["render",r]]);export{u as __pageData,h as default};
